console.log('RAW freebusy output:', JSON.stringify($input.all()[0].json, null, 2));

const raw = $input.all()[0].json;
let busy = [];
if (raw.calendars && raw.calendars.primary && Array.isArray(raw.calendars.primary.busy)) {
  busy = raw.calendars.primary.busy;
} else if (Array.isArray(raw.busy)) {
  busy = raw.busy;
} else {
  console.log('Could not find busy array — treating calendar as empty.');
}

const slots = [];
const tz = 'Asia/Manila';

const start = DateTime.now().setZone(tz).plus({ days: 1 }).startOf('day');

const phHolidays2026 = [
  '2026-01-01','2026-02-17','2026-03-20','2026-04-02','2026-04-03',
  '2026-04-04','2026-04-09','2026-05-01','2026-05-20','2026-06-12',
  '2026-08-21','2026-08-31','2026-11-01','2026-11-02','2026-11-30',
  '2026-12-08','2026-12-24','2026-12-25','2026-12-30','2026-12-31',
];

const holidayDates = new Set(phHolidays2026);

busy.forEach(b => {
  const bStart = DateTime.fromISO(b.start);
  const bEnd = DateTime.fromISO(b.end);
  if (bEnd.diff(bStart, 'hours').hours >= 24) {
    holidayDates.add(bStart.toISODate());
  }
});

const staticData = $getWorkflowStaticData('global');
const cancelledSlots = new Set(staticData._cancelledSlots || []);

const effectiveBusy = busy.filter(b => !cancelledSlots.has(b.start));

for (let d = 0; d < 7; d++) {
  const currentDay = start.plus({ days: d });
  const dateStr = currentDay.toISODate();

  if (currentDay.weekday >= 6) continue;
  if (holidayDates.has(dateStr)) continue;

  for (let h = 8; h < 17; h++) {
    if (h === 12) continue;

    for (let m = 0; m < 60; m += 30) {
      const slot = currentDay.set({ hour: h, minute: m });
      const slotEnd = slot.plus({ minutes: 30 });

      const isBusy = effectiveBusy.some(b =>
        slot < DateTime.fromISO(b.end) && slotEnd > DateTime.fromISO(b.start)
      );

      if (!isBusy) slots.push(slot.toISO());
    }
  }
}

const clientEmail = $('Set — clientName + clientEmail').item.json.clientEmail;
const clientName  = $('Set — clientName + clientEmail').item.json.clientName;

staticData[clientEmail] = {
  slots,
  clientName,
  clientEmail,
  storedAt: Date.now()
};

console.log(`Stored ${slots.length} slots for ${clientEmail}`);

return [{ json: { slots, clientName, clientEmail, slotCount: slots.length } }];

const email = $json.query.email || '';
const name  = $json.query.name  || '';

const staticData = $getWorkflowStaticData('global');
const record = staticData[email];

if (!record || !record.slots || record.slots.length === 0) {
  return [{ json: {
    renderError: true,
    errorMessage: 'Your session has expired or no slots were found. Please start over.',
    name,
    email
  } }];
}

const bookedSlots = new Set(staticData._bookedSlots || []);
const availableSlots = record.slots.filter(s => !bookedSlots.has(s));

const options = availableSlots.map(s => {
  const dt = new Date(s);
  const label = dt.toLocaleString('en-PH', {
    weekday: 'short', month: 'short', day: 'numeric',
    hour: '2-digit', minute: '2-digit',
    timeZone: 'Asia/Manila'
  });
  return `<option value="${s}">${label}</option>`;
}).join('');

return [{ json: {
  renderError: false,
  name: record.clientName,
  email: record.clientEmail,
  slotCount: availableSlots.length,
  optionsHtml: options
} }];

