const staticData = $getWorkflowStaticData('global');
const email      = $json.clientEmail;
const newSlot    = $json.selectedSlot;
const record     = staticData[email];
const oldSlot    = record ? record.selectedSlot : null;

if (!staticData._bookedSlots) staticData._bookedSlots = [];

if (oldSlot) {
  staticData._bookedSlots = staticData._bookedSlots.filter(s => s !== oldSlot);
}

if (!staticData._bookedSlots.includes(newSlot)) {
  staticData._bookedSlots.push(newSlot);
}

if (record) {
  record.selectedSlot = newSlot;
  record.bookingId    = $json.bookingId;
}

return [{ json: $json }];

